/**
 * Test 1: Admin Pages Smoke Test
 * Verifies all remaining admin pages load without critical errors
 */
test.describe('Smoke Test — Remaining Admin Pages', () => {
  for (const page of REMAINING_ADMIN_PAGES) {
    test(`${page.name} (${page.path}) loads successfully`, async ({ page: p }) => {
      const errors: string[] = [];

      // Capture JS errors
      p.on('pageerror', (error) => {
        // Ignore Supabase/placeholder errors
        if (error.message.includes('supabase')) return;
        if (error.message.includes('__ENV__')) return;
        // Ignore demo function errors
        if (/is not defined/.test(error.message) && /createDemo|Auth|mekongAgents/.test(error.message)) return;
        // Ignore duplicate custom element registration
        if (error.message.includes('CustomElementRegistry')) return;
        errors.push(error.message);
      });

      // Ignore Supabase console errors
      p.on('console', (msg) => {
        if (msg.type() === 'error' && msg.text().includes('Supabase')) return;
      });

      const response = await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });

      // 1. HTTP 200
      expect(response?.status()).toBe(200);

      // 2. No critical JS errors (auth redirects are expected)
      expect(errors.length, `Critical errors on ${page.path}: ${errors.join(', ')}`).toBeLessThanOrEqual(0);
    });
  }
});

