/**
 * Test 3: Admin Pages — Basic Structure Validation
 * Verifies each admin page has required HTML structure
 * Note: Skipped for partial HTML components
 */
test.describe.skip('Structure Validation — Admin Pages', () => {
  for (const page of REMAINING_ADMIN_PAGES) {
    test(`${page.name} has valid HTML structure`, async ({ page: p }) => {
      await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });

      // 1. Has DOCTYPE
      const doctype = await p.evaluate(() => {
        const node = document.firstChild;
        return node?.nodeType === 10; // DocumentType Node
      });
      expect(doctype, `Missing DOCTYPE on ${page.path}`).toBe(true);

      // 2. Has <html> with lang attribute
      const htmlLang = await p.getAttribute('html', 'lang');
      expect(htmlLang, `Missing lang attribute on ${page.path}`).toBeTruthy();

      // 3. Has <head> and <body>
      const hasHead = await p.evaluate(() => document.head !== null);
      const hasBody = await p.evaluate(() => document.body !== null);
      expect(hasHead, `Missing <head> on ${page.path}`).toBe(true);
      expect(hasBody, `Missing <body> on ${page.path}`).toBe(true);

      // 4. Has <title>
      const title = await p.title();
      expect(title.length, `Empty or missing <title> on ${page.path}`).toBeGreaterThan(0);

      // 5. Has viewport meta
      const viewport = await p.getAttribute('meta[name="viewport"]', 'content');
      expect(viewport, `Missing viewport meta on ${page.path}`).toBeTruthy();

      // 6. Has charset meta
      const charset = await p.querySelector('meta[charset]');
      expect(charset, `Missing charset meta on ${page.path}`).toBeTruthy();
    });
  }
});

