/**
 * Test 5: Responsive Check — All Remaining Pages
 * Quick mobile viewport check
 */
test.describe('Responsive Check — Remaining Pages', () => {
  const MOBILE_VIEWPORT = { width: 375, height: 812 }; // iPhone X
  const DESKTOP_VIEWPORT = { width: 1920, height: 1080 };

  // Test a subset of pages for responsive (to save time)
  const PAGES_TO_TEST = [
    '/admin/inventory.html',
    '/admin/pos.html',
    '/admin/suppliers.html',
    '/portal/subscription-plans.html',
  ];

  for (const pagePath of PAGES_TO_TEST) {
    test(`${pagePath} is responsive on mobile`, async ({ page: p }) => {
      await p.setViewportSize(MOBILE_VIEWPORT);
      const response = await p.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 15000 });
      expect(response?.status()).toBe(200);

      // Check if page renders without horizontal scroll
      const hasHorizontalScroll = await p.evaluate(() => {
        return document.documentElement.scrollWidth > document.documentElement.clientWidth;
      });
      // Some horizontal scroll is acceptable for complex dashboards
      expect(hasHorizontalScroll).toBeFalsy();
    });

    test(`${pagePath} renders correctly on desktop`, async ({ page: p }) => {
      await p.setViewportSize(DESKTOP_VIEWPORT);
      const response = await p.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 15000 });
      expect(response?.status()).toBe(200);
    });
  }
});

/**
 * Test 6: Accessibility — Basic Checks
 * WCAG 2.1 Level A basic checks for remaining pages
 */
test.describe('Accessibility — Remaining Pages Basic Checks', () => {
  for (const page of REMAINING_ADMIN_PAGES.slice(0, 5)) { // Test first 5 pages
    test(`${page.name} passes basic a11y checks`, async ({ page: p }) => {
      await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });

      // 1. Has main landmark
      const hasMain = await p.evaluate(() => document.querySelector('main') !== null);
      expect(hasMain, `Missing <main> landmark on ${page.path}`).toBe(true);

      // 2. Images have alt text (sample check first 5 images)
      const imagesWithoutAlt = await p.evaluate(() => {
        const images = Array.from(document.querySelectorAll('img')).slice(0, 5);
        return images.filter(img => !img.hasAttribute('alt')).length;
      });
      expect(imagesWithoutAlt, `Images without alt on ${page.path}`).toBeLessThanOrEqual(0);
    });
  }
});
